const results = $input.first().json.results || [];
const wh = $('Webhook Novo Contato').first().json;

const origin = results.find(t =>
  Array.isArray(t.tags) &&
  t.tags.includes('impulsis_ativo') &&
  ['open','pending','hold'].includes(t.status)
);

if (!origin) {
  return [{ json: {
    found: false,
    reason: 'origin_not_found',
    new_ticket_id: wh.body.ticket_id,
    requester_id: wh.body.requester_id
  } }];
}

return [{ json: {
  found: true,
  new_ticket_id: wh.body.ticket_id,
  requester_id: wh.body.requester_id,
  origin_ticket_id: origin.id,
  origin_subject: origin.subject,
  origin_group_id: origin.group_id,
  assignee_id_fallback: origin.assignee_id
} }];

const ctx = $('Extrair Ticket Original').first().json;
const comments = $input.first().json.comments || [];

const impulsis_comment = [...comments].reverse().find(c =>
  c.public === false &&
  c.body &&
  c.body.includes('Nome do Template:') &&
  c.body.includes('Destinatario:')
);

let sender_agent_id = null;
let sender_source = 'nao_encontrado';

if (impulsis_comment) {
  sender_agent_id = impulsis_comment.author_id;
  sender_source = 'comentario_impulsis_mais_recente';
}

const assignee_id_final = sender_agent_id || ctx.assignee_id_fallback;
const using_fallback = !sender_agent_id;

return [{ json: {
  found: ctx.found,
  new_ticket_id: ctx.new_ticket_id,
  requester_id: ctx.requester_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  origin_group_id: ctx.origin_group_id,
  assignee_id_final,
  assignee_id_fallback: ctx.assignee_id_fallback,
  sender_agent_id,
  sender_source,
  using_fallback
} }];

const ctx = $('Extrair Agente Disparador do Impulsis').first().json;
const results = $input.first().json.results || [];

const duplicate = results.find(t =>
  String(t.id) !== String(ctx.new_ticket_id) &&
  ['open','pending','hold'].includes(t.status)
);

return [{ json: {
  found: ctx.found,
  new_ticket_id: ctx.new_ticket_id,
  requester_id: ctx.requester_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  origin_group_id: ctx.origin_group_id,
  assignee_id_final: ctx.assignee_id_final,
  assignee_id_fallback: ctx.assignee_id_fallback,
  sender_agent_id: ctx.sender_agent_id,
  sender_source: ctx.sender_source,
  using_fallback: ctx.using_fallback,
  duplicate_child_found: !!duplicate,
  duplicate_child_id: duplicate ? duplicate.id : null
} }];

const agentResponse = $('Buscar Dados do Agente').first().json;
const groupMembershipResponse = $('Buscar Grupos do Agente').first().json;
const ctx = $('Validar Duplicidade de Filho').first().json;

const agent = agentResponse.user || {};
const memberships = groupMembershipResponse.group_memberships || [];

const isZendeskAgent = ['agent', 'admin'].includes(agent.role);
const activeMemberships = memberships.filter(m => !m.deleted);

// Preferir o grupo padrão do próprio usuário Zendesk, quando ele também aparece nas memberships.
// Isso evita cair no grupo do ticket original e respeita o grupo operacional do agente.
const agentDefaultGroupId = agent.default_group_id || null;
const membershipFromUserDefault = agentDefaultGroupId
  ? activeMemberships.find(m => String(m.group_id) === String(agentDefaultGroupId))
  : null;

const defaultMembership = activeMemberships.find(m => m.default === true);
const selectedMembership = membershipFromUserDefault || defaultMembership || activeMemberships[0] || null;
const group_id_final = selectedMembership ? selectedMembership.group_id : null;

let routing_error = null;
if (!ctx.assignee_id_final) {
  routing_error = 'assignee_id_final_missing';
} else if (!agent.id) {
  routing_error = 'agent_not_found';
} else if (!isZendeskAgent) {
  routing_error = 'user_is_not_agent_or_admin';
} else if (!group_id_final) {
  routing_error = 'agent_has_no_active_group_membership';
}

const can_route_to_agent = !routing_error;

const fonte = ctx.using_fallback
  ? 'assignee do ticket original (fallback - comentario Impulsis nao localizado)'
  : 'comentario privado mais recente do Impulsis';

const nota = [
  'Retorno Impulsis roteado automaticamente.',
  '',
  'Ticket de origem: #' + ctx.origin_ticket_id + ' (' + ctx.origin_subject + ')',
  'Grupo original do ticket de origem: ' + (ctx.origin_group_id || 'nao informado'),
  'Agente responsavel pelo novo ticket: ' + (agent.name || 'nao identificado') + ' (' + (agent.email || 'sem email') + ')',
  'Grupo padrao do agente: ' + (agentDefaultGroupId || 'nao informado'),
  'Grupo selecionado para roteamento: ' + (group_id_final || 'nao encontrado'),
  'Origem do assignee: ' + fonte,
  '',
  'O ticket de origem permanece aberto e sera encerrado automaticamente apos o fechamento deste ticket.'
].join('\n');

const erro = [
  'Falha no roteamento automatico do retorno Impulsis.',
  '',
  'Motivo: ' + (routing_error || 'sem erro'),
  'Ticket de origem: #' + ctx.origin_ticket_id,
  'Agente pretendido: ' + (ctx.assignee_id_final || 'nao informado'),
  'Grupo padrao do agente: ' + (agentDefaultGroupId || 'nao informado'),
  'Grupo original do ticket de origem: ' + (ctx.origin_group_id || 'nao informado'),
  '',
  'Este workflow nao enviou o ticket para o grupo original para evitar redistribuicao automatica para agente incorreto.',
  'Ajuste o grupo do agente ou revise a regra de roteamento antes de reprocessar.'
].join('\n');

return [{ json: {
  new_ticket_id: ctx.new_ticket_id,
  origin_ticket_id: ctx.origin_ticket_id,
  origin_subject: ctx.origin_subject,
  origin_group_id: ctx.origin_group_id,
  assignee_id_final: ctx.assignee_id_final,
  group_id_final,
  agent_default_group_id: agentDefaultGroupId,
  agent_name: agent.name,
  agent_email: agent.email,
  agent_role: agent.role,
  group_membership_id_final: selectedMembership ? selectedMembership.id : null,
  nota_interna: nota,
  nota_erro_roteamento: erro,
  usando_fallback: ctx.using_fallback,
  sender_source: ctx.sender_source,
  can_route_to_agent,
  routing_error
} }];
